// Prepare compact BLE payload for abnormal detection
// BLE has limited MTU (~20-512 bytes), so we send a compact JSON
// without the full image. The image stays on disk.
var compact = {
    t: 'ABN',
    c: msg.payload.prediction,
    p: Math.round(msg.payload.confidence * 100),
    ts: Date.now()
};
msg.payload = Buffer.from(JSON.stringify(compact));
return msg;

// Compact BLE payload for normal reading
var compact = {
    t: 'OK',
    p: Math.round(msg.payload.confidence * 100),
    ts: Date.now()
};
msg.payload = Buffer.from(JSON.stringify(compact));
return msg;

